"use client"

import { useEffect, useState } from "react"
import { SidebarProvider, SidebarInset } from "@/components/ui/sidebar"
import { AppSidebar } from "@/components/app-sidebar"
import { AppHeader } from "@/components/app-header"
import { Dashboard } from "@/components/modules/dashboard"
import { OrganizationModule, PositionModule } from "@/components/modules/organization"
import { EmployeeModule } from "@/components/modules/employee"
import { AttendanceModule } from "@/components/modules/attendance"
import { RecruitmentModule } from "@/components/modules/recruitment"
import { SalaryModule } from "@/components/modules/salary"
import { PerformanceModule } from "@/components/modules/performance"
import { AnalyticsModule } from "@/components/modules/analytics"
import { SettingsModule } from "@/components/modules/settings"
import { PlaceholderModule } from "@/components/modules/placeholder"
import { ScrollArea } from "@/components/ui/scroll-area"

const placeholderConfig: Record<string, { title: string; description: string }> = {
  "talent-pool": { title: "人才库", description: "管理未录用但优秀的候选人，便于后续联系和推荐" },
  onboarding: { title: "入职管理", description: "管理新员工入职流程、入职材料准备和入职培训安排" },
  probation: { title: "试用期管理", description: "管理新入职员工的试用期考核及转正流程" },
  transfer: { title: "异动管理", description: "管理员工在部门间的调动及职位变更" },
  resignation: { title: "离职管理", description: "管理员工离职申请、审批及交接手续" },
  contract: { title: "合同管理", description: "管理员工劳动合同签订、续签和到期提醒" },
  "employee-change": { title: "人事变动", description: "管理员工调岗、晋升、降级及离职等人事变动记录" },
  leave: { title: "假期管理", description: "管理年假、调休等假期额度设置和余额查询" },
  benefits: { title: "员工福利", description: "管理各类员工福利政策、节日福利和礼品发放" },
  "self-service": { title: "员工自助", description: "员工可在此查看个人档案、工资条及申请假勤" },
  "manager-service": { title: "经理自助", description: "经理可在此审批下属申请、查看团队报表" },
  kpi: { title: "KPI指标", description: "管理绩效考核指标体系、权重设置和评分标准" },
  reports: { title: "报表中心", description: "生成和下载各类人力资源报表，支持自定义报表配置" },
  permissions: { title: "权限管理", description: "基于RBAC模型管理系统角色和权限分配" },
}

function ModuleContent({ activeModule }: { activeModule: string }) {
  switch (activeModule) {
    case "dashboard":
      return <Dashboard />
    case "organization":
      return <OrganizationModule />
    case "position":
      return <PositionModule />
    case "employee":
      return <EmployeeModule />
    case "attendance":
      return <AttendanceModule />
    case "recruitment":
      return <RecruitmentModule />
    case "salary":
      return <SalaryModule />
    case "performance":
      return <PerformanceModule />
    case "analytics":
      return <AnalyticsModule />
    case "settings":
      return <SettingsModule />
    default:
      const config = placeholderConfig[activeModule]
      if (config) {
        return <PlaceholderModule title={config.title} description={config.description} />
      }
      return (
        <PlaceholderModule 
          title="功能开发中" 
          description={`模块 [${activeModule}] 正在加紧开发中，敬请期待...`} 
        />
      )
  }
}

export default function HRSystemPage() {
  const [activeModule, setActiveModule] = useState("dashboard")

  // Sync state with URL hash
  useEffect(() => {
    const handleHashChange = () => {
      const hash = window.location.hash.replace("#", "")
      if (hash) {
        setActiveModule(hash)
      }
    }

    // Initial load
    handleHashChange()

    window.addEventListener("hashchange", handleHashChange)
    return () => window.removeEventListener("hashchange", handleHashChange)
  }, [])

  const handleModuleChange = (module: string) => {
    setActiveModule(module)
    window.location.hash = module
  }

  return (
    <SidebarProvider>
      <AppSidebar activeModule={activeModule} onModuleChange={handleModuleChange} />
      <SidebarInset>
        <AppHeader activeModule={activeModule} />
        <ScrollArea className="flex-1">
          <div className="p-6">
            <ModuleContent activeModule={activeModule} />
          </div>
        </ScrollArea>
      </SidebarInset>
    </SidebarProvider>
  )
}
